mapper.update:
/* 무효전력 수정 */ UPDATE tb_reactive
std_timestamp = #{entity.stdTimestamp},
rctv_val = #{entity.rctvVal},
neg_rctv_val = #{entity.negRctvVal},
mod_date = NOW(),
WHERE rctv_idx = #{entity.rctvIdx}

mapper.delete:
/* 무효전력 삭제 */
DELETE FROM tb_reactive 
 WHERE rctv_idx = #{rctvIdx}

mapper.select:
/* 무효전력 전체 개수 조회 */
SELECT COUNT(*) AS CNT
  FROM tb_reactive
 WHERE rctv_idx = #{rctvIdx}
